import{c as o,i as n}from"./chunk-BDL73CAT.js";var d=[{id:"a-voz-dos-sete-trovoes",slug:"a-voz-dos-sete-trovoes",title:"A Voz dos Sete Trov\xF5es",preachedDate:"1964-12-31",formattedDate:"31 de dezembro de 1964",location:"Jeffersonville, Indiana",summary:"Uma mensagem profunda sobre os sete trov\xF5es do Apocalipse e os mist\xE9rios guardados para o tempo do fim, pregada na v\xE9spera de Ano Novo de 1964.",paragraphs:[{number:1,text:"Que grande privil\xE9gio temos esta manh\xE3 de estar novamente aqui na casa de Deus. E confio que, ao virmos hoje, viemos com expectativa, buscando que o Esp\xEDrito Santo nos visite. \xC9 o fim do ano, um tempo em que olhamos para tr\xE1s e tamb\xE9m olhamos para frente."},{number:2,text:'Sabe, quando aqueles trov\xF5es pronunciaram as suas vozes, Jo\xE3o estava prestes a escrever. Mas a Voz veio do c\xE9u e disse: "Sela as coisas que os sete trov\xF5es pronunciaram, e n\xE3o as escreves." Era um mist\xE9rio, um segredo guardado para o tempo do fim.'},{number:3,text:"E assim \xE9 hoje, estamos parados no limiar de uma nova dispensa\xE7\xE3o. O mundo est\xE1 em turbul\xEAncia, tudo est\xE1 sendo sacudido. Mas temos um Reino que n\xE3o pode ser sacudido. Temos uma Palavra que est\xE1 estabelecida para sempre nos c\xE9us."},{number:4,text:"Quero que voc\xEA note a simplicidade de Deus. Deus \xE9 sempre simples. Tentamos torn\xE1-Lo t\xE3o complicado com nossa educa\xE7\xE3o e nossos sistemas, mas Deus permanece em Sua simples Palavra. Se voc\xEA puder simplesmente crer naquela Palavra hoje, o mesmo poder que ressuscitou Jesus dos mortos vivificar\xE1 os seus corpos mortais."},{number:5,text:"Pense nisso! Antes da funda\xE7\xE3o do mundo, Ele te conhecia. Ele te viu. Seu nome estava escrito no Livro da Vida do Cordeiro. N\xE3o \xE9 daquele que quer, nem daquele que corre, mas de Deus que usa de miseric\xF3rdia. Oh, como devemos louv\xE1-Lo por Seu favor imerecido."},{number:6,text:"E ent\xE3o a s\xE9tima voz \u2014 aquela mensagem do s\xE9timo anjo \u2014 ela deve revelar todas as coisas. Porque o mist\xE9rio de Deus deve ser consumado. A coisa mais simples do mundo, contudo escondida dos s\xE1bios e entendidos e revelada aos humildes e mansos."},{number:7,text:"Enquanto estamos aqui nesta \xFAltima hora, neste \xFAltimo dia, irm\xE3o, irm\xE3, deixe-me dizer-lhe: prepare-se. Prepare-se para a vinda do Senhor. Porque quando Ele vier, vir\xE1 como um rel\xE2mpago que sai do oriente e se mostra at\xE9 ao ocidente. Esteja pronto."}]},{id:"o-arrebatamento",slug:"o-arrebatamento",title:"O Arrebatamento",preachedDate:"1965-12-04",formattedDate:"4 de dezembro de 1965",location:"Shreveport, Louisiana",summary:"Uma exposi\xE7\xE3o detalhada sobre os eventos do arrebatamento da Igreja, a ressurrei\xE7\xE3o dos mortos em Cristo e a transforma\xE7\xE3o dos vivos.",paragraphs:[{number:1,text:"Esta manh\xE3 desejo falar sobre algo que est\xE1 muito pr\xF3ximo do meu cora\xE7\xE3o. \xC9 o arrebatamento da Igreja. O arrebatamento \u2014 eu gostaria de estabelecer isso diretamente da Palavra."},{number:2,text:'Encontramos em 1 Tessalonicenses 4:16 \u2014 "Porque o pr\xF3prio Senhor descer\xE1 do c\xE9u com alarido, com voz de arcanjo, e com a trombeta de Deus; e os que morreram em Cristo ressuscitar\xE3o primeiro."'},{number:3,text:"Agora, note \u2014 h\xE1 tr\xEAs coisas aqui. Primeiro: um alarido. Segundo: a voz do arcanjo. Terceiro: a trombeta de Deus. Tr\xEAs coisas. E eu acredito que essas tr\xEAs coisas s\xE3o separadas uma da outra por um per\xEDodo de tempo."},{number:4,text:"O alarido desperta os mortos em Cristo. A voz do arcanjo os transforma. E ent\xE3o a trombeta os recolhe para juntar-se ao Senhor nos ares. Oh, que pensamento maravilhoso!"},{number:5,text:"E voc\xEA, crente verdadeiro, que vive neste dia, voc\xEA ver\xE1 isso acontecer. Voc\xEA estar\xE1 aqui quando o Senhor vier. Fique firme na Palavra. N\xE3o vacile. A promessa \xE9 certa."}]},{id:"quem-e-este-melquisedeque",slug:"quem-e-este-melquisedeque",title:"Quem \xE9 Este Melquisedeque?",preachedDate:"1965-02-21",formattedDate:"21 de fevereiro de 1965",location:"Jeffersonville, Indiana",summary:"Uma revela\xE7\xE3o sobre a identidade de Melquisedeque nas Escrituras e sua rela\xE7\xE3o com o eterno sacerd\xF3cio de Jesus Cristo.",paragraphs:[{number:1,text:'Gostaria de ler esta manh\xE3 de G\xEAnesis 14, come\xE7ando no vers\xEDculo 18. "E Melquisedeque, rei de Sal\xE9m, trouxe p\xE3o e vinho; e era sacerdote do Deus Alt\xEDssimo."'},{number:2,text:'Quem era Melquisedeque? Essa tem sido uma quest\xE3o que tem intrigado te\xF3logos por s\xE9culos. Mas a B\xEDblia o descreve como "sem pai, sem m\xE3e, sem genealogia; que n\xE3o tem come\xE7o de dias, nem fim de vida, mas sendo feito semelhante ao Filho de Deus, permanece sacerdote para sempre."'},{number:3,text:"Agora, se isso descreve um homem que n\xE3o tinha pai ou m\xE3e, n\xE3o tinha come\xE7o de dias nem fim de vida \u2014 ent\xE3o este n\xE3o era um homem. Porque todo homem tem um pai, tem uma m\xE3e, tem um come\xE7o de dias."},{number:4,text:"Melquisedeque era o pr\xF3prio Filho de Deus, manifestado em forma humana antes de Sua encarna\xE7\xE3o em Bel\xE9m. Ele era o Deus eterno aparecendo a Abra\xE3o, recebendo os d\xEDzimos, aben\xE7oando o patriarca."},{number:5,text:"E Jesus Cristo, nosso Sumo Sacerdote, \xE9 sacerdote segundo a ordem de Melquisedeque \u2014 uma ordem eterna, sem come\xE7o e sem fim. Que funda\xE7\xE3o maravilhosa sobre a qual repousa nossa f\xE9!"}]},{id:"a-presenca-de-deus",slug:"a-presenca-de-deus",title:"A Presen\xE7a de Deus",preachedDate:"1963-03-17",formattedDate:"17 de mar\xE7o de 1963",location:"Jeffersonville, Indiana",summary:"Uma mensagem sobre como reconhecer e cultivar a presen\xE7a de Deus em nossa vida di\xE1ria, baseada nas experi\xEAncias dos homens de Deus nas Escrituras.",paragraphs:[{number:1,text:"Esta manh\xE3 quero falar sobre algo muito precioso para o cora\xE7\xE3o de todo crente verdadeiro \u2014 a presen\xE7a de Deus. N\xE3o a religi\xE3o. N\xE3o um conjunto de regras. Mas a presen\xE7a real e viva do Deus vivo."},{number:2,text:'Quando Mois\xE9s disse: "Se a Tua presen\xE7a n\xE3o for conosco, n\xE3o nos fa\xE7as partir daqui" \u2014 ele sabia algo que muitos de n\xF3s precisamos aprender. A presen\xE7a de Deus \xE9 tudo. Sem ela, nada mais importa.'},{number:3,text:'E Deus respondeu a Mois\xE9s dizendo: "A Minha presen\xE7a ir\xE1 contigo, e Eu te darei descanso." Que promessa! A mesma promessa que est\xE1 dispon\xEDvel para voc\xEA e para mim hoje.'},{number:4,text:"Mas como cultivamos essa presen\xE7a? Atrav\xE9s da obedi\xEAncia \xE0 Sua Palavra. Atrav\xE9s da ora\xE7\xE3o sincera. Atrav\xE9s de um cora\xE7\xE3o que busca a Deus em tudo \u2014 n\xE3o apenas quando precisamos de algo."},{number:5,text:"Que possamos ser um povo que, como Enoque, caminha com Deus. N\xE3o caminhando ao lado da religi\xE3o, mas com o pr\xF3prio Deus \u2014 ouvindo Sua voz, seguindo Sua dire\xE7\xE3o, vivendo em Sua presen\xE7a."}]},{id:"o-noivado-e-a-vinda-do-senhor",slug:"o-noivado-e-a-vinda-do-senhor",title:"O Noivado e a Vinda do Senhor",preachedDate:"1965-11-27",formattedDate:"27 de novembro de 1965",location:"Shreveport, Louisiana",summary:"Uma poderosa exposi\xE7\xE3o sobre o noivado espiritual entre Cristo e Sua noiva, a Igreja, e os sinais que apontam para Seu retorno iminente.",paragraphs:[{number:1,text:"Quero falar esta manh\xE3 sobre o noivado e a vinda do Senhor. Estamos vivendo nos dias finais. O tempo est\xE1 se esgotando. Cada sinal que Jesus mencionou est\xE1 acontecendo diante de nossos olhos."},{number:2,text:"O noivado espiritual \xE9 real. Cristo tem uma noiva. Essa noiva \xE9 composta por aqueles que nasceram de novo, que foram lavados pelo sangue, que receberam o Esp\xEDrito Santo e caminham na Palavra."},{number:3,text:"E assim como um noivado terreno prepara para o casamento, o Esp\xEDrito Santo est\xE1 hoje preparando a noiva de Cristo para a grande uni\xE3o que est\xE1 por vir. Cada prova, cada tribula\xE7\xE3o, \xE9 parte desse processo de prepara\xE7\xE3o."},{number:4,text:"N\xE3o se perca no mundo. O mundo est\xE1 passando. As modas est\xE3o passando. Os sistemas est\xE3o passando. Mas a Palavra de Deus permanece para sempre. Ancore sua vida na Palavra."},{number:5,text:"O Noivo est\xE1 vindo. Tenhamos certeza de que nossas l\xE2mpadas est\xE3o cheias de \xF3leo \u2014 cheias do Esp\xEDrito Santo \u2014 prontas para sair ao Seu encontro no grande dia da Sua vinda."}]}];var m=class r{messages=d;getAllMessages(){return o(this.messages)}getMessageById(s){return o(this.messages.find(e=>e.id===s))}getReaderData(s){let e=this.messages.findIndex(u=>u.id===s);if(e===-1)return o(null);let a=this.messages[e],t=e>0?this.messages[e-1]:null,i=e<this.messages.length-1?this.messages[e+1]:null;return o({messageId:a.id,title:a.title,preachedDate:a.preachedDate,formattedDate:a.formattedDate,location:a.location,previousMessage:t?{id:t.id,title:t.title}:null,nextMessage:i?{id:i.id,title:i.title}:null,paragraphs:a.paragraphs})}searchMessages(s){let e=s.trim().toLowerCase();return e?o(this.messages.filter(a=>a.title.toLowerCase().includes(e)||a.location.toLowerCase().includes(e)||a.formattedDate.toLowerCase().includes(e))):o(this.messages)}static \u0275fac=function(e){return new(e||r)};static \u0275prov=n({token:r,factory:r.\u0275fac,providedIn:"root"})};export{m as a};
